function ModelNetDebug:AddDebugMessage(index, msgId, pbPack, proto)
	self._recordInd = self._recordInd + 1
	if self._recordInd > 2147483647 then
		self._recordInd = 0
	end
	local msgItem = {
		recordId = self._recordInd,
		index = index, 
		msgId = msgId, 
		pbPack = pbPack,
		pbStream = proto,
		streamTable = LProtoHelper.ProtoToPureTable(proto),
		pbBuff = LProtoHelper.ConvertToString(pbPack),
		msgMode = 0,
		sendCount = 0,
		msgName = LProtoHelper.GetProtoName(msgId) or "unknow",
		time = os.time()
	}

	local isIgnoreRecord = msgItem.msgId == LProtoIds.TickReq

	if not self._isNetBreakpoint or isIgnoreRecord then

		self:SendDebugMessageItem(msgItem, false)
	else
		self._breakSendMsgMap[msgItem] = true
		table.insert(self._breakSendMsgList, msgItem)
	end

	if isIgnoreRecord then
		return
	end

	if not self._curMsg then
		self._curMsg = msgItem
	end


	table.insert(self._recordSendMsgList, 1, msgItem)
	if #self._recordSendMsgList > 100  then
		table.remove(self._recordSendMsgList)
	end

	FireEvent("net_debug_add_message")
end
function ModelNetDebug:SendDebugMessageToIndex(targetIndex, bForceResend)
	local curCnt = #self._breakSendMsgList
	if curCnt == 0 then
		return
	end
	
	local msgItem = nil
	local curIndex = 0
	while curIndex < targetIndex do
		curIndex = curIndex + 1
		
		msgItem = self._breakSendMsgList[1]
		if not msgItem then
			break
		end
		self:SendDebugMessageItem(msgItem, bForceResend)
		
		curCnt = #self._breakSendMsgList
		if curCnt > 1 then
			table.remove(self._breakSendMsgList, 1)
			self._breakSendMsgMap[msgItem] = nil
		end
	end

end

function ModelNetDebug:SendDebugMessageItem(msgItem, bForceResend)
	if not msgItem then
		return
	end
	
	if not bForceResend and msgItem.sendCount > 0 then
		return
	end
	
	local onceSendCount = self._onceSendCount
	if onceSendCount < 1 then
		onceSendCount = 1
	end

	if onceSendCount > 1 then
		for idx = 1, onceSendCount do
			msgItem.sendCount = msgItem.sendCount + 1

			if msgItem.msgMode ==  0 then
				gLNetManager:SendMessagePackDebug(msgItem.pbPack,msgItem.pbStream,msgItem.msgId,self._msgHeadKey)
			elseif msgItem.msgMode ==  1 then
				gLNetManager:SendMessageBuffDebug(msgItem.pbBuff,msgItem.pbStream,msgItem.msgId)
			elseif msgItem.msgMode ==  2 then
				gLNetManager:SendMessageDebug(msgItem.pbStream,msgItem.msgId,true,self._msgHeadKey)
			end
		end
	else
		msgItem.sendCount = msgItem.sendCount + 1

		if msgItem.msgMode ==  0 then
			gLNetManager:SendMessagePackDebug(msgItem.pbPack,msgItem.pbStream,msgItem.msgId,self._msgHeadKey)
		elseif msgItem.msgMode ==  1 then
			gLNetManager:SendMessageBuffDebug(msgItem.pbBuff,msgItem.pbStream,msgItem.msgId)
		elseif msgItem.msgMode ==  2 then
			gLNetManager:SendMessageDebug(msgItem.pbStream,msgItem.msgId,true,self._msgHeadKey)
		end
	end

end

